mapper.select:
select document_access_rule_id, company_id, document_id, role_id, department_id, status, created_at
from document_access_rules
where company_id = #{companyId,jdbcType=VARCHAR}
  and document_id = #{documentId,jdbcType=VARCHAR}
  and upper(coalesce(trim(status), '')) = 'ACTIVE'
order by created_at asc
